// Build a restaurant-style menu list payload.
// Each section maps to a category; each row is an item the user can tap.

const creds = $input.first().json;

const payload = {
  number: creds.targetNumber,
  title: "🍕 NEXTGEN Pizza Menu",
  description: "Tap a category to see what's available, then pick an item to order.",
  buttonText: "View Menu",
  footerText: "Powered by n8n + Evolution API",
  values: [
    {
      title: "Pizzas",
      rows: [
        { title: "Margherita",   description: "Classic tomato, mozzarella, basil — 7 JOD", rowId: "pizza_margherita" },
        { title: "Pepperoni",    description: "Pepperoni + mozzarella — 8 JOD",          rowId: "pizza_pepperoni" },
        { title: "Veggie Deluxe", description: "Peppers, olives, mushrooms — 8 JOD",       rowId: "pizza_veggie" }
      ]
    },
    {
      title: "Drinks",
      rows: [
        { title: "Cola",      description: "330ml can — 1 JOD",       rowId: "drink_cola" },
        { title: "Water",     description: "500ml bottle — 0.5 JOD",  rowId: "drink_water" }
      ]
    },
    {
      title: "Actions",
      rows: [
        { title: "View Cart",  description: "See what you've ordered", rowId: "action_view_cart" },
        { title: "Checkout",   description: "Place your order now",     rowId: "action_checkout" }
      ]
    }
  ]
};

return [{ json: { ...creds, payload } }];
